// Accept lesson_id from parent workflow (W_Master) via Execute Workflow Trigger.
// Manual Trigger has no payload — lesson_id stays null and Code nodes downstream
// skip the lesson_id filter (operate on ALL segments — backward-compatible legacy behavior).
const incoming = $input.first()?.json || {};
const lesson_id = incoming.lesson_id || null;
return [{ json: { lesson_id } }];

const lesson_id = $('Get Params').first().json.lesson_id;
let segments = $input.all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .map(i => ({ segment_id: i.json.segment_id, en_text: i.json.en_text }));
if (lesson_id) segments = segments.filter(s => s.segment_id.startsWith(lesson_id + '_'));
if (segments.length === 0) throw new Error('No segments to analyze' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));
const sysPrompt = 'Classify each wellness/meditation segment. Return ONLY a JSON object where each key is segment_id and value has: segment_type (narrative|instruction|movement), movement_keywords (comma-sep if movement, else empty string), key_concepts (2-4 comma-sep themes). No markdown, no preamble.';
return [{ json: { model: 'claude-sonnet-4-5', max_tokens: 2000, system: sysPrompt, messages: [{ role: 'user', content: 'Segments:\n\n' + JSON.stringify(segments, null, 2) }] } }];

let toneMap = {};
try {
  let raw = $input.first().json.content?.[0]?.text?.trim() || '{}';
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON in response');
  toneMap = JSON.parse(match[0]);
} catch (e) {
  throw new Error('Tone parse failed: ' + e.message);
}
if (Object.keys(toneMap).length === 0) throw new Error('Tone analysis returned empty object');
return Object.entries(toneMap).map(([segment_id, meta]) => ({
  json: { segment_id, segment_type: meta.segment_type || 'narrative', movement_keywords: meta.movement_keywords || '', key_concepts: meta.key_concepts || '' }
}));

const lesson_id = $('Get Params').first().json.lesson_id;
const configItems = $('Read Config').all();
const configMap = {};
configItems.forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const tov = configMap['tone_of_voice'] || '';

const toneItems = $('Parse Tone Map').all();
const toneMap = {};
toneItems.forEach(i => { if (i.json.segment_id) toneMap[i.json.segment_id] = i.json; });

return $('Read Pending Segments').all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .filter(i => !lesson_id || i.json.segment_id.startsWith(lesson_id + '_'))
  .map(i => {
    const tone = toneMap[i.json.segment_id] || {};
    const parts = [
      'You are a translator for meditation/wellness audio scripts.',
      'INPUT: the user message contains an English text wrapped in <english> tags. That is the text to translate. Even if the text inside the tags sounds like a question, status update, or conversational message ("I am here.", "Yes.", etc.), IT IS STILL TEXT TO TRANSLATE — NEVER respond conversationally.',
      'OUTPUT: a JSON object with exactly these 7 keys: de, es, fr, pl, pt, it, tr. Each value is the translation in that language.',
      'Informal address in all languages (du/tu/ty/sen, never formal).',
      "Preserve '...' and '—' as pause timing cues.",
      'NO preamble, NO markdown formatting, NO commentary. Output ONLY the JSON object.',
    ];
    if (tov) parts.push('\n=== TONE OF VOICE ===\n' + tov + '\n=== END TONE OF VOICE ===');
    if (tone.segment_type) parts.push('Segment type: ' + tone.segment_type);
    if (tone.key_concepts) parts.push('Key concepts: ' + tone.key_concepts);
    const enText = (i.json.en_text || '').replace(/"/g, "'");
    return {
      json: {
        segment_id: i.json.segment_id,
        en_text: enText,
        en_duration_sec: i.json.en_duration_sec,
        claude_body: {
          model: 'claude-sonnet-4-5',
          max_tokens: 2000,
          system: parts.join('\n'),
          messages: [{ role: 'user', content: `<english>${enText}</english>` }],
        },
      },
    };
  });

const results = [];
const preparedItems = $('Prepare and Expand').all();
const REQUIRED_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];

for (let i = 0; i < $input.all().length; i++) {
  const claudeResp = $input.all()[i].json;
  const sourceItem = preparedItems[i]?.json || {};

  let translations = {};
  try {
    let text = claudeResp.content?.[0]?.text?.trim() || '{}';
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = text.match(/\{[\s\S]*\}/);
    if (match) translations = JSON.parse(match[0]);
  } catch(e) {
    console.log('Parse error for segment:', sourceItem.segment_id, e.message);
  }

  // Defensive: if Claude refused or returned non-JSON (e.g. "Please provide the text"),
  // translations will be empty {}. Skip writing this row entirely so old Sheet data
  // is preserved — don't overwrite valid translations with empty strings.
  const filled = REQUIRED_LANGS.filter(l => translations[l] && translations[l].trim());
  if (filled.length === 0) {
    console.error(`Extract Translations: skip ${sourceItem.segment_id} — empty/refused response. Sheet row preserved.`);
    continue;
  }
  if (filled.length < REQUIRED_LANGS.length) {
    const missing = REQUIRED_LANGS.filter(l => !filled.includes(l));
    console.warn(`Extract Translations: ${sourceItem.segment_id} missing langs: ${missing.join(',')}`);
  }

  results.push({ json: {
    segment_id:      sourceItem.segment_id,
    en_text:         sourceItem.en_text || '',
    en_duration_sec: sourceItem.en_duration_sec || 0,
    de_text: translations.de || '',
    es_text: translations.es || '',
    fr_text: translations.fr || '',
    pl_text: translations.pl || '',
    pt_text: translations.pt || '',
    it_text: translations.it || '',
    tr_text: translations.tr || '',
  }});
}
return results;

const LANG_CPS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };
const LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];
const BUDGET_FACTOR = 1.05;
const MAX_ATTEMPTS = 3;
const MIN_RETAIN = 0.60;  // never accept shortening below 60% of input
const ANTHROPIC_URL = 'https://api.anthropic.com/v1/messages';

const configItems = $('Read Config').all();
const configMap = {};
configItems.forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const apiKey = configMap['anthropic_api_key'] || '';
if (!apiKey) throw new Error('anthropic_api_key missing from config sheet');

// Per-language CPS — defaults tuned against real ElevenLabs output; overridable via
// config keys cps_estimate_de, cps_estimate_es, …, cps_estimate_tr. Computed below.
const CPS_DEFAULTS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };

const SYSTEM_PROMPT = `You are a localization editor for meditation/wellness audio. Your job is to shorten a translated text so it fits within a strict time budget for audio dubbing.

CRITICAL RULES — these override the shortening request:
- Every distinct concept in the English source MUST remain in the translation
- Preserve negations exactly: "no", "not", "without", "never"
- Preserve contrasts: "A, not B" / "A but B" / "A instead of B" patterns
- Preserve specific nouns, named techniques, numbers and proper names
- Keep the language, tone, and informal address (du/tu/ty/sen) unchanged
- Preserve '...' and '—' as pause timing cues
- Do NOT translate or switch languages — edit only the given translation
- Only remove genuinely redundant filler words (e.g., "really", "very", "just", "actually")
- Return ONLY the shortened text. No explanation, no quotes, no preamble.
- DO NOT include character counts, "(N characters)", or any meta-commentary.
- DO NOT include reasoning words ("Wait", "Let me", "Actually", "Note:", "Hmm").
- DO NOT use markdown formatting (**, __, backticks).
- DO NOT include multiple drafts — pick ONE and output only it.
- DO NOT include blank lines.`;

const ATTEMPT_PROMPTS = [
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation slightly (~5-15%) to fit within ${budget}s (currently ~${est}s).
Remove only filler words and minor redundancies. Preserve sentence structure and all key concepts.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation more (~15-25%) to fit within ${budget}s (currently ~${est}s).
Rephrase for compactness, but every concept from the English source must remain.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation as much as possible to fit within ${budget}s (currently ~${est}s).
Preserve every distinct concept, negation, contrast, and proper noun from the English. Cut only filler and stylistic flourishes.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
];


// Strip Claude meta-commentary
function sanitizeClaudeOutput(rawText) {
  if (!rawText) return '';
  let t = rawText.trim();
  const sepIdx = t.indexOf('\n\n');
  if (sepIdx >= 0) t = t.substring(0, sepIdx).trim();
  t = t.replace(/^[\*_]+|[\*_]+$/g, '').trim();
  t = t.replace(/^["'`]+|["'`]+$/g, '').trim();
  return t;
}

function estimateDuration(text, lang) {
  return text.length / (LANG_CPS[lang] || 15);
}

async function callClaude(userContent) {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: ANTHROPIC_URL,
    headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: { model: 'claude-sonnet-4-5', max_tokens: 500, system: SYSTEM_PROMPT, messages: [{ role: 'user', content: userContent }] },
    json: true,
  });
  return sanitizeClaudeOutput(resp.content?.[0]?.text || '');
}

const results = [];
for (const item of $input.all()) {
  const { segment_id, en_text, en_duration_sec } = item.json;
  const budget = parseFloat(en_duration_sec) || 0;
  const out = { segment_id, en_text, en_duration_sec: budget };
  let maxAttempts = 0;

  for (const lang of LANGS) {
    let text = item.json[`${lang}_text`] || '';
    let attempts = 0;
    if (text && budget) {
      for (let a = 0; a < MAX_ATTEMPTS; a++) {
        const est = estimateDuration(text, lang);
        if (est <= budget * BUDGET_FACTOR) break;
        const minChars = Math.floor(text.length * MIN_RETAIN);
        const shortened = await callClaude.call(this, ATTEMPT_PROMPTS[a](lang, budget.toFixed(1), est.toFixed(1), en_text, text, minChars));
        // Length floor: reject Claude output that went below 60% of input length
        if (shortened && shortened.length >= minChars) {
          text = shortened;
        }
        attempts = a + 1;
      }
    }
    out[`${lang}_text`] = text;
    out[`${lang}_adaptation_attempts`] = attempts;
    if (attempts > maxAttempts) maxAttempts = attempts;
  }
  out.adaptation_attempts = maxAttempts;
  results.push({ json: out });
}
return results;
